async function timed(label, fn) {
  const t0 = Date.now();
  try {
    const out = await fn();
    results.steps[label] = { ok: true, ms: Date.now() - t0, ...out };
    console.log(`[OK] ${label} (${Date.now() - t0}ms)`);
  } catch (e) {
    results.steps[label] = { ok: false, ms: Date.now() - t0, error: e.message };
    console.log(`[FAIL] ${label} (${Date.now() - t0}ms) — ${e.message}`);
  }
}

