  });

  // 3. Owner-AI chat with passwordless token
  if(token){
    await timed('owner_ai_chat',async()=>{
      const r=await fetch(RENDER_BACKEND+'/api/ivx/owner-ai',{method:'POST',headers:{'Content-Type':'application/json',Authorization:'Bearer '+token},body:JSON.stringify({message:'Reply with the single word: ALIVE',email:OWNER_EMAIL})});
      const text=await r.text();
      let body;try{body=JSON.parse(text);}catch{body={raw:text.slice(0,400)};}
      return {status:r.status,answer:body?.answer,model:body?.model,conversationId:body?.conversationId};
    });

    // 4. Auth diagnostic
    await timed('auth_diagnostic',async()=>{
      const r=await fetch(RENDER_BACKEND+'/api/ivx/owner-ai/auth-diagnostic',{method:'POST',headers:{'Content-Type':'application/json',Authorization:'Bearer '+token},body:JSON.stringify({email:OWNER_EMAIL})});
      const text=await r.text();
      let body;try{body=JSON.parse(text);}catch{body={raw:text.slice(0,300)};}
      return {status:r.status,accepted:body?.accepted??body?.ok,ownerEmailAllowlisted:body?.ownerAllowlist?.emailAllowlisted,supabaseSessionValid:body?.checks?.supabaseSessionValid,tokenExpired:body?.checks?.tokenExpired,secondsUntilExpiry:body?.checks?.secondsUntilExpiry};
    });
  }

  // 5. GitHub
  await timed('github_main',async()=>{
    const r=await fetch('https://api.github.com/repos/ibb142/rork-global-real-estate-invest/commits/main',{headers:{Authorization:'Bearer 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',Accept:'application/vnd.github+json','User-Agent':'IVX-Audit'}});
    const d=await r.json();
    return {status:r.status,sha:d.sha,message:(d.commit?.message??'').slice(0,120)};
  });

  // 6. Render deploy
  await timed('render_deploy',async()=>{
    const r=await fetch('https://api.render.com/v1/services/srv-d7t9ivreo5us73ftose0/deploys?limit=2',{headers:{Authorization:'Bearer rnd_1H0XCquMZQTRyAnHgbEv8dVWYPVs',Accept:'application/json'}});
    const d=await r.json();
    const deploys=(Array.isArray(d)?d:(d.deploys||[])).slice(0,2).map(x=>{const dd=x.deploy||x;return{status:dd.status,commit:dd.commit?.id,updated:dd.updatedAt};});
    return {status:r.status,deploys};
  });

  const finishedAt=new Date().toISOString();
